// tests/e2e/helpers.rs

use std::process::{Command, Output, Stdio};
use std::time::Duration;
use std::io::{Write, BufRead, BufReader};
use std::thread;

/// Configuration for E2E test runs
pub struct E2ETestConfig {
    pub timeout: Duration,
    pub env_vars: Vec<(String, String)>,
    pub clear_env: Vec<String>,
    pub capture_stderr: bool,
    pub capture_stdout: bool,
}

impl Default for E2ETestConfig {
    fn default() -> Self {
        Self {
            timeout: Duration::from_secs(30),
            env_vars: vec![],
            clear_env: vec!["MCP_CLIENT".into(), "CLAUDE_CODE".into()],
            capture_stderr: true,
            capture_stdout: true,
        }
    }
}

impl E2ETestConfig {
    pub fn agent_mode() -> Self {
        Self {
            env_vars: vec![("MCP_CLIENT".into(), "test-agent".into())],
            ..Default::default()
        }
    }

    pub fn human_mode() -> Self {
        Self {
            env_vars: vec![("FASTMCP_FORCE_COLOR".into(), "1".into())],
            clear_env: vec!["MCP_CLIENT".into(), "CLAUDE_CODE".into(), "NO_COLOR".into()],
            ..Default::default()
        }
    }
}

/// Run a test server and capture output
pub struct TestServerRunner {
    config: E2ETestConfig,
}

impl TestServerRunner {
    pub fn new(config: E2ETestConfig) -> Self {
        Self { config }
    }

    /// Run test server binary and capture output
    pub fn run_server(&self, args: &[&str]) -> TestServerResult {
        let start = std::time::Instant::now();

        let mut cmd = Command::new(env!("CARGO_BIN_EXE_test_server"));
        cmd.args(args)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped());

        // Set environment variables
        for (key, value) in &self.config.env_vars {
            cmd.env(key, value);
        }

        // Clear environment variables
        for key in &self.config.clear_env {
            cmd.env_remove(key);
        }

        eprintln!("[E2E] Starting server with args: {:?}", args);
        eprintln!("[E2E] Environment: {:?}", self.config.env_vars);

        let mut child = cmd.spawn().expect("Failed to spawn test server");

        // Capture output with timeout
        let stdout_handle = child.stdout.take().unwrap();
        let stderr_handle = child.stderr.take().unwrap();

        let stdout_reader = BufReader::new(stdout_handle);
        let stderr_reader = BufReader::new(stderr_handle);

        let stdout_lines: Vec<String> = stdout_reader.lines()
            .filter_map(Result::ok)
            .collect();
        let stderr_lines: Vec<String> = stderr_reader.lines()
            .filter_map(Result::ok)
            .collect();

        let status = child.wait().expect("Failed to wait for server");
        let duration = start.elapsed();

        eprintln!("[E2E] Server completed in {:?} with status: {:?}", duration, status);
        eprintln!("[E2E] Stdout lines: {}", stdout_lines.len());
        eprintln!("[E2E] Stderr lines: {}", stderr_lines.len());

        TestServerResult {
            stdout: stdout_lines,
            stderr: stderr_lines,
            exit_code: status.code().unwrap_or(-1),
            duration,
        }
    }

    /// Send JSON-RPC messages to running server via stdin
    pub fn run_with_messages(&self, messages: &[&str]) -> TestServerResult {
        let mut cmd = Command::new(env!("CARGO_BIN_EXE_test_server"));
        cmd.stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped());

        for (key, value) in &self.config.env_vars {
            cmd.env(key, value);
        }

        let mut child = cmd.spawn().expect("Failed to spawn");

        // Send messages to stdin
        if let Some(stdin) = child.stdin.as_mut() {
            for msg in messages {
                eprintln!("[E2E] Sending: {}", msg);
                writeln!(stdin, "{}", msg).expect("Failed to write");
            }
        }

        // Capture output...
        // (similar to above)
        todo!()
    }
}

/// Result of running a test server
#[derive(Debug)]
pub struct TestServerResult {
    pub stdout: Vec<String>,
    pub stderr: Vec<String>,
    pub exit_code: i32,
    pub duration: Duration,
}

impl TestServerResult {
    /// Check if stderr contains a string (for rich output)
    pub fn stderr_contains(&self, needle: &str) -> bool {
        self.stderr.iter().any(|line| line.contains(needle))
    }

    /// Check if stdout contains a string (for JSON-RPC)
    pub fn stdout_contains(&self, needle: &str) -> bool {
        self.stdout.iter().any(|line| line.contains(needle))
    }

    /// Check that stdout contains ONLY valid JSON-RPC
    pub fn stdout_is_valid_jsonrpc(&self) -> bool {
        self.stdout.iter().all(|line| {
            if line.trim().is_empty() {
                return true;
            }
            serde_json::from_str::<serde_json::Value>(line).is_ok()
        })
    }

    /// Check for ANSI escape codes
    pub fn has_ansi_codes(&self) -> bool {
        let combined = self.stderr.join("\n");
        combined.contains("\x1b[") || combined.contains("\033[")
    }

    /// Assert no ANSI in stdout (critical for agent mode)
    pub fn assert_stdout_no_ansi(&self) {
        let combined = self.stdout.join("\n");
        assert!(
            !combined.contains("\x1b[") && !combined.contains("\033["),
            "stdout must not contain ANSI codes! Found in stdout:\n{}",
            combined
        );
    }

    /// Print detailed diagnostics
    pub fn print_diagnostics(&self) {
        eprintln!("\n=== E2E Test Result ===");
        eprintln!("Exit code: {}", self.exit_code);
        eprintln!("Duration: {:?}", self.duration);
        eprintln!("\n--- STDOUT ({} lines) ---", self.stdout.len());
        for (i, line) in self.stdout.iter().enumerate() {
            eprintln!("{:4}: {}", i + 1, line);
        }
        eprintln!("\n--- STDERR ({} lines) ---", self.stderr.len());
        for (i, line) in self.stderr.iter().enumerate() {
            eprintln!("{:4}: {}", i + 1, line);
        }
        eprintln!("======================\n");
    }
}
