+            request_id: 1,
+        };
+        // Bearer works
+        assert!(
+            verifier
+                .verify(
+                    &ctx(),
+                    req,
+                    &AccessToken {
+                        scheme: "Bearer".to_string(),
+                        token: "tok".to_string(),
+                    },
+                )
+                .is_ok()
+        );
+        // Token works
+        assert!(
+            verifier
+                .verify(
+                    &ctx(),
+                    req,
+                    &AccessToken {
+                        scheme: "Token".to_string(),
+                        token: "tok".to_string(),
+                    },
+                )
+                .is_ok()
+        );
+        // Basic does not
+        assert!(
+            verifier
+                .verify(
+                    &ctx(),
+                    req,
+                    &AccessToken {
+                        scheme: "Basic".to_string(),
+                        token: "tok".to_string(),
+                    },
+                )
+                .is_err()
+        );
+    }
